INTRO: PROC OPTIONS(MAIN);
  DCL X FIXED BIN(31);
  DCL Y FIXED BIN(31);
  DCL TOTAL FIXED BIN(31);

  X = 10;
  Y = 20;
  TOTAL = X + Y;

  PUT SKIP LIST('SUM =', TOTAL);
END INTRO;

CORE: PROC OPTIONS(MAIN);
  DCL ARR(5) FIXED BIN(31);
  DCL I FIXED BIN(31);

  DO I = 1 TO 5;
    ARR(I) = I * 2;
  END;

  DO I = 1 TO 5;
    PUT SKIP LIST('ARR(', I, ') =', ARR(I));
  END;
END CORE;

ADVANCED: PROC OPTIONS(MAIN);
  DCL STR CHAR(50) VAR;
  DCL LEN FIXED BIN(31);

  STR = 'HELLO, PL/I!';
  LEN = LENGTH(STR);

  PUT SKIP LIST('TEXT:', STR);
  PUT SKIP LIST('LENGTH:', LEN);
END ADVANCED;
